import{_ as r,o as e,c as a,a2 as o}from"./chunks/framework.DjxoKHTk.js";const b=JSON.parse('{"title":"高級燒肉店特製蔥鹽醬","description":"聖凱師不藏私分享！利用鹽巴讓蔥與洋蔥自然脫水凝聚香氣，最後加上關鍵柴魚粉完美交融。","frontmatter":{"title":"高級燒肉店特製蔥鹽醬","description":"聖凱師不藏私分享！利用鹽巴讓蔥與洋蔥自然脫水凝聚香氣，最後加上關鍵柴魚粉完美交融。"},"headers":[],"relativePath":"中式/特製蔥鹽醬.md","filePath":"中式/特製蔥鹽醬.md","lastUpdated":1781138667000}'),n={name:"中式/特製蔥鹽醬.md"};function d(l,t,s,i,g,h){return e(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="高級燒肉店特製蔥鹽醬" tabindex="-1">高級燒肉店特製蔥鹽醬 <a class="header-anchor" href="#高級燒肉店特製蔥鹽醬" aria-label="Permalink to &quot;高級燒肉店特製蔥鹽醬&quot;">​</a></h1><p><strong>來源：</strong> <a href="https://youtu.be/R6XpARMIny8" target="_blank" rel="noreferrer">YouTube - 鏸鈺教室（聖凱師）</a><strong>分享日期：</strong> 2026/06/08 <strong>主廚：</strong> 錵鑶聖凱師</p><hr><blockquote><p><strong>聖凱師不藏私分享！</strong> 以前開燒肉店時偷偷放的秘密武器。利用鹽巴讓蔥與洋蔥自然脫水凝聚香氣，最後加上關鍵「柴魚粉」完美交融，把蔥鹽風味從 100 分拉升到 120 分！不論配燒肉、牛舌或煮泡麵都是絕配。</p></blockquote><hr><h2 id="📝-食材" tabindex="-1">📝 食材 <a class="header-anchor" href="#📝-食材" aria-label="Permalink to &quot;📝 食材&quot;">​</a></h2><table tabindex="0"><thead><tr><th>食材</th><th style="text-align:center;">用量</th><th>處理</th></tr></thead><tbody><tr><td>🧅 <strong>洋蔥</strong></td><td style="text-align:center;"><strong>1 頭</strong></td><td>去頭尾剖半，切成碎末</td></tr><tr><td>🌿 <strong>青蔥</strong></td><td style="text-align:center;"><strong>100 公克</strong>（約5大根）</td><td>切成寬蔥花，保留口感不切太細</td></tr><tr><td>🧂 <strong>白胡椒鹽</strong></td><td style="text-align:center;"><strong>2 公克</strong>（重口味可加至 4 克）</td><td></td></tr><tr><td>🧂 <strong>鹽巴</strong></td><td style="text-align:center;"><strong>0.5 公克</strong></td><td>用於調味與脫水</td></tr><tr><td>🫒 <strong>香油或白麻油</strong></td><td style="text-align:center;"><strong>15 公克</strong>（約 2 大匙）</td><td></td></tr><tr><td>🐟 <strong>柴魚粉</strong></td><td style="text-align:center;"><strong>1 湯匙</strong> 🥄</td><td>⭐ <strong>隱藏版靈魂秘密！</strong></td></tr></tbody></table><hr><h2 id="👨‍🍳-做法" tabindex="-1">👨‍🍳 做法 <a class="header-anchor" href="#👨‍🍳-做法" aria-label="Permalink to &quot;👨‍🍳 做法&quot;">​</a></h2><h3 id="步驟-1-洋蔥切碎末技巧-🧅" tabindex="-1">步驟 1：洋蔥切碎末技巧 🧅 <a class="header-anchor" href="#步驟-1-洋蔥切碎末技巧-🧅" aria-label="Permalink to &quot;步驟 1：洋蔥切碎末技巧 🧅&quot;">​</a></h3><ol><li>洋蔥去頭尾、對半剝皮</li><li>利用洋蔥一層一層的天然構造，<strong>切面朝下</strong></li><li>先<strong>橫向劃刀</strong>（間隔約 0.5 公分，後端留 0.5 公分勿切斷）</li><li>接著直接<strong>直刀切下去</strong>，洋蔥會自然散落成完美的碎末</li><li>最後沒劃到刀的尾端倒過來隨意切碎即可</li></ol><h3 id="步驟-2-切製寬蔥花-🌿" tabindex="-1">步驟 2：切製寬蔥花 🌿 <a class="header-anchor" href="#步驟-2-切製寬蔥花-🌿" aria-label="Permalink to &quot;步驟 2：切製寬蔥花 🌿&quot;">​</a></h3><p>洗淨瀝乾的青蔥抓成一把。</p><blockquote><p>💡 <strong>聖凱師重點：</strong> 蔥鹽醬的蔥<strong>不用切得非常細</strong>，像牛肉麵配的那種正常寬度即可。切太細反而會失去咀嚼時的脆彈口感！</p></blockquote><h3 id="步驟-3-加入基礎調味攪拌" tabindex="-1">步驟 3：加入基礎調味攪拌 <a class="header-anchor" href="#步驟-3-加入基礎調味攪拌" aria-label="Permalink to &quot;步驟 3：加入基礎調味攪拌&quot;">​</a></h3><p>將洋蔥末與蔥花全部放入大碗中，依序加入：</p><ul><li>白胡椒鹽 2~4 克</li><li>鹽巴 0.5 克</li><li>香油/白麻油 15 克（約 2 湯匙）</li></ul><p>用湯匙<strong>充分攪拌均勻</strong></p><h3 id="步驟-4-冰鎮脫水凝聚風味-❄️" tabindex="-1">步驟 4：冰鎮脫水凝聚風味 ❄️ <a class="header-anchor" href="#步驟-4-冰鎮脫水凝聚風味-❄️" aria-label="Permalink to &quot;步驟 4：冰鎮脫水凝聚風味 ❄️&quot;">​</a></h3><blockquote><p>剛拌好時會覺得好像沒什麼味道。</p></blockquote><p>將大碗放入<strong>冰箱冷藏靜置 15~20 分鐘</strong>，利用鹽分讓食材自然脫水（分量會稍微變少凝聚）。</p><ul><li>✅ 有效去除洋蔥與青蔥的<strong>生辣刺激感</strong></li><li>✅ 讓味道變得<strong>溫潤融合</strong></li></ul><h3 id="步驟-5-120分秘密兵器提鮮-🐟🔥" tabindex="-1">步驟 5：120分秘密兵器提鮮 🐟🔥 <a class="header-anchor" href="#步驟-5-120分秘密兵器提鮮-🐟🔥" aria-label="Permalink to &quot;步驟 5：120分秘密兵器提鮮 🐟🔥&quot;">​</a></h3><p>從冰箱取出蔥鹽醬（此時已呈現油亮入味狀態）。</p><p>加入關鍵的 <strong>1 湯匙柴魚粉</strong>，徹底攪拌均勻。</p><blockquote><p>⭐ <strong>秘密原理：</strong> 柴魚粉會完全溶解在香油與蔥汁中，吃的人只會覺得極度鮮美、層次豐富，卻完全看不到固體、猜不出加了什麼！</p></blockquote><hr><h2 id="🍽️-推薦吃法" tabindex="-1">🍽️ 推薦吃法 <a class="header-anchor" href="#🍽️-推薦吃法" aria-label="Permalink to &quot;🍽️ 推薦吃法&quot;">​</a></h2><table tabindex="0"><thead><tr><th>搭配</th><th>說明</th></tr></thead><tbody><tr><td>🥩 <strong>燒肉</strong></td><td>燒肉店經典搭配，解膩提鮮</td></tr><tr><td>🐂 <strong>牛舌</strong></td><td>絕配！蔥鹽+烤牛舌經典組合</td></tr><tr><td>🍜 <strong>泡麵</strong></td><td>聖凱師親推！加一匙立刻升級</td></tr><tr><td>🥟 <strong>水餃</strong></td><td>取代醬油沾醬，清爽新風味</td></tr><tr><td>🍚 <strong>拌飯</strong></td><td>拌入白飯就是一碗蔥鹽飯</td></tr></tbody></table><hr><h2 id="⏱️-總時間" tabindex="-1">⏱️ 總時間 <a class="header-anchor" href="#⏱️-總時間" aria-label="Permalink to &quot;⏱️ 總時間&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">階段</th><th style="text-align:center;">時間</th></tr></thead><tbody><tr><td style="text-align:left;">準備</td><td style="text-align:center;">10 分鐘</td></tr><tr><td style="text-align:left;">冰鎮</td><td style="text-align:center;">15~20 分鐘</td></tr><tr><td style="text-align:left;"><strong>總計</strong></td><td style="text-align:center;"><strong>約 30 分鐘</strong></td></tr></tbody></table><hr><p><em>由 Hermes 於 2026/06/08 整理，依據聖凱師影片食譜</em></p>',34)])])}const u=r(n,[["render",d]]);export{b as __pageData,u as default};
